
"use client"

import { useState, useEffect, useMemo } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogClose } from "@/components/ui/dialog";
import { 
  Zap, Loader2, Navigation, Timer, Flag, Trophy, MapPin, Star, Clock, Play, Target, X, Gauge, ShieldAlert, Radio, Activity
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection, query, where, getCountFromServer } from "firebase/firestore";
import { useDriving, RunMode } from "@/context/driving-context";
import { RenderCarIcon } from "@/components/icons/car-icons";

const RouteMap = dynamic(() => import("../../components/telemetry/route-map"), { 
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center bg-zinc-900/50 rounded-3xl">
      <Loader2 className="w-6 h-6 animate-spin text-red-500" />
    </div>
  )
});

type ReportType = 'Radar' | 'Polici' | 'Kontrollë';

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const { 
    speed, isDriving, peakSpeed, tripTime, tripDistance, hasGps, 
    currentCoords, routePoints, telemetry, startTime,
    runMode, dragTime, isDragFinished, isNavigating, currentStep, currentRoadName, distanceToNextStep, routeData,
    setRunMode, startTrip, stopTrip, resetTrip, requestWakeLock, clearNavigation
  } = useDriving();
  
  const [mounted, setMounted] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [cityRank, setCityRank] = useState<number | null>(null);
  const [kosovoRank, setKosovoRank] = useState<number | null>(null);
  const [isRankingLoading, setIsRankingLoading] = useState(false);
  
  const { toast } = useToast();

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  const calculateRanks = async () => {
    if (!db || !profile) return;
    setIsRankingLoading(true);
    
    try {
      const publicRunsCol = collection(db, "public_runs");
      let kosovoQuery;
      let cityQuery;

      const runTypeLabel = runMode === 'free' ? 'Top Speed' : runMode === '0-100' ? '0-100' : runMode === '100-200' ? '100-200' : '1/4 Mile';
      const val = runMode === 'free' ? peakSpeed : dragTime;

      if (!val || val <= 0) {
        setIsRankingLoading(false);
        return;
      }

      if (runMode === 'free') {
        kosovoQuery = query(publicRunsCol, where("runType", "==", "Top Speed"), where("peakSpeedKmH", ">", val));
        if (profile.city) {
          cityQuery = query(publicRunsCol, where("city", "==", profile.city), where("runType", "==", "Top Speed"), where("peakSpeedKmH", ">", val));
        }
      } else {
        kosovoQuery = query(publicRunsCol, where("runType", "==", runTypeLabel), where("dragTime", "<", val));
        if (profile.city) {
          cityQuery = query(publicRunsCol, where("city", "==", profile.city), where("runType", "==", runTypeLabel), where("dragTime", "<", val));
        }
      }

      const [kosovoSnapshot, citySnapshot] = await Promise.all([
        getCountFromServer(kosovoQuery),
        cityQuery ? getCountFromServer(cityQuery) : Promise.resolve(null)
      ]);

      setKosovoRank(kosovoSnapshot.data().count + 1);
      if (citySnapshot) {
        setCityRank(citySnapshot.data().count + 1);
      }
    } catch (e) {
      console.error("Ranking failed:", e);
    } finally {
      setIsRankingLoading(false);
    }
  };

  useEffect(() => {
    if (isDragFinished && mounted && !showSummary) {
      setTimeout(() => {
        setShowSummary(true);
        calculateRanks();
      }, 300);
    }
  }, [isDragFinished, mounted]);

  const handleStartMission = () => {
    startTrip();
    requestWakeLock();
  };

  const handleStopMission = () => {
    stopTrip();
    setTimeout(() => {
      setShowSummary(true);
      calculateRanks();
    }, 400);
  };

  const formatTime = (seconds: number) => {
    const min = Math.floor(seconds / 60);
    const sec = Math.floor(seconds % 60);
    return `${min.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}`;
  };

  const avgSpeed = useMemo(() => {
    if (tripTime <= 0) return 0;
    return Math.round((tripDistance / 1000) / (tripTime / 3600));
  }, [tripDistance, tripTime]);

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Kosovë",
      runType: runMode === 'free' ? 'Top Speed' : runMode === '0-100' ? '0-100' : runMode === '100-200' ? '100-200' : '1/4 Mile',
      startTime: startTime?.toISOString() || new Date().toISOString(),
      endTime: new Date().toISOString(),
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      dragTime: dragTime,
      telemetry: telemetry,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };
    
    const userRunsCol = collection(db, "users", user.uid, "runs");
    addDocumentNonBlocking(userRunsCol, runData);
    
    const publicRunsCol = collection(db, "public_runs");
    addDocumentNonBlocking(publicRunsCol, runData);
    
    toast({ title: "Ruajtur", description: "Të dhënat u sinkronizuan." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
    setCityRank(null);
    setKosovoRank(null);
  };

  const rpm = useMemo(() => {
    if (speed === 0) return 800;
    const gear = Math.floor(speed / 60) + 1;
    const speedInGear = speed % 60;
    const baseRpm = 1200 + (gear * 100);
    const calculated = baseRpm + (speedInGear * 110);
    return Math.min(Math.floor(calculated), 8000);
  }, [speed]);

  const handleQuickReport = async (type: ReportType) => {
    if (!db || !currentCoords || !user?.uid) {
      toast({ variant: "destructive", title: "Gabim", description: "GPS kërkohet." });
      return;
    }
    
    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type,
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: "Dashboard",
      city: profile?.city || "Kosovë",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });
    
    toast({ title: "Raportuar", description: `${type} u shënua.` });
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  return (
    <div className="flex flex-col min-h-full bg-black text-foreground pb-24 overflow-x-hidden safe-top relative no-scrollbar">
      {/* Header Info */}
      <div className="p-5 space-y-4 z-20 shrink-0 apple-slide-up">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-zinc-900/50 border border-white/5 flex items-center justify-center">
                <RenderCarIcon type={profile?.profileIcon} className="w-5 h-5 text-red-500" />
             </div>
             <div>
                <h1 className="text-[10px] font-black uppercase tracking-tight text-white">{profile?.username || "SHOFER"}</h1>
                <div className="flex items-center gap-1.5 mt-0.5">
                  <div className={cn("w-1 h-1 rounded-full", isDriving ? "bg-red-500" : "bg-zinc-700")} />
                  <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">
                    {isDriving ? "LIVE TELEMETRY" : "READY"}
                  </span>
                </div>
             </div>
          </div>
          <Badge variant="outline" className="text-[7px] font-black uppercase border-white/5 text-muted-foreground bg-white/5 py-1 px-3 tracking-widest rounded-lg">
            {hasGps ? "GPS ACTIVE" : "WAITING FOR GPS"}
          </Badge>
        </div>

        {!isNavigating && (
          <div className="grid grid-cols-3 gap-2.5 stagger-1 apple-slide-up">
            {[
              { id: 'Radar', label: 'RADAR', emoji: '🚨', color: 'red' },
              { id: 'Polici', label: 'POLICI', emoji: '🚔', color: 'blue' },
              { id: 'Kontrollë', label: 'KONTROLL', emoji: '🚗', color: 'zinc' }
            ].map((item) => (
              <Button 
                key={item.id}
                onClick={() => handleQuickReport(item.id as ReportType)} 
                className={cn(
                  "h-12 flex flex-col items-center justify-center gap-0.5 rounded-xl border bg-white/5 border-white/5 transition-all active:scale-95",
                  item.color === 'red' && "text-red-500",
                  item.color === 'blue' && "text-blue-400",
                  item.color === 'zinc' && "text-zinc-400"
                )}
              >
                <span className="text-sm">{item.emoji}</span>
                <span className="text-[7px] font-black uppercase tracking-widest">{item.label}</span>
              </Button>
            ))}
          </div>
        )}
      </div>

      {/* Main Dashboard Interaction Area */}
      <div className="flex-1 flex flex-col items-center justify-center relative px-6 py-2">
        {/* Navigation HUD Mode */}
        {isNavigating && (
          <div className="w-full max-w-[360px] mb-8 stagger-1 apple-slide-up">
            <Card className="bg-[#1c2a3d]/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border-white/10 shadow-2xl">
              <div className="flex items-center gap-5">
                <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center">
                  <Navigation className="w-7 h-7 text-white" />
                </div>
                <div className="flex-1 min-w-0">
                  <h2 className="text-sm font-black text-white leading-tight uppercase tracking-tight">
                    {currentStep?.instruction || "Vazhdoni drejt"}
                  </h2>
                  <p className="text-[8px] font-black text-white/40 uppercase tracking-widest mt-1">
                    {distanceToNextStep >= 1000 ? `${(distanceToNextStep / 1000).toFixed(1)} km` : `${distanceToNextStep} m`} • {currentRoadName}
                  </p>
                </div>
              </div>
            </Card>
          </div>
        )}

        {/* Mode Selector */}
        {!isNavigating && (
          <div className="w-full max-w-[280px] mb-6 z-20 apple-scale-in">
            <div className="bg-zinc-900/50 backdrop-blur-3xl p-1 rounded-2xl border border-white/5 flex gap-1">
              {[
                { id: 'free', label: 'LIRË', icon: Navigation },
                { id: '0-100', label: '0-100', icon: Zap },
                { id: '100-200', label: '100-200', icon: Clock },
                { id: '1/4mile', label: '1/4 M', icon: Flag }
              ].map((mode) => (
                <button 
                  key={mode.id}
                  onClick={() => !isDriving && setRunMode(mode.id as RunMode)}
                  className={cn(
                    "flex-1 h-9 flex flex-col items-center justify-center rounded-lg transition-all",
                    runMode === mode.id ? "bg-red-600 text-white" : "text-muted-foreground hover:bg-white/5",
                    isDriving && "opacity-40 cursor-not-allowed"
                  )}
                >
                  <mode.icon className="w-3 h-3" />
                  <span className="text-[6px] font-black uppercase tracking-widest mt-0.5">{mode.label}</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Gauge Ring - Transition based on isNavigating */}
        <div className={cn(
          "relative flex items-center justify-center mx-auto mb-6 transition-all duration-1000 apple-scale-in",
          isNavigating ? "w-48 h-48 opacity-80" : "w-full aspect-square max-w-[280px]"
        )}>
          <svg viewBox="0 0 400 400" className="w-full h-full transform -rotate-90 absolute inset-0">
            <circle cx="200" cy="200" r="185" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-white/[0.05]" />
            <circle
              cx="200" cy="200" r="185"
              stroke="currentColor" strokeWidth="3"
              fill="transparent"
              strokeDasharray={2 * Math.PI * 185}
              style={{ 
                strokeDashoffset: (2 * Math.PI * 185) - (rpm / 8000) * (2 * Math.PI * 185),
                transition: 'stroke-dashoffset 0.8s cubic-bezier(0.16, 1, 0.3, 1)'
              }}
              className={cn("transition-all", rpm > 7000 ? "text-red-600" : "text-red-500/30")}
            />
          </svg>
          
          <div className="z-20 flex flex-col items-center justify-center">
            <span className={cn(
              "font-black tracking-tighter leading-none tabular-nums text-white transition-all duration-700", 
              isNavigating ? "text-5xl" : (speed > 99 ? "text-7xl" : "text-8xl")
            )}>
              {speed}
            </span>
            <span className="text-[10px] font-black uppercase tracking-[0.4em] text-red-600 mt-2">KM/H</span>
          </div>
        </div>

        {/* Stats Grid */}
        <div className={cn(
          "grid grid-cols-2 gap-3 w-full max-w-[280px] z-20 mb-8 stagger-2 apple-slide-up transition-all duration-1000",
          isNavigating ? "opacity-40 scale-90" : "opacity-100"
        )}>
           <div className="bg-zinc-900/40 border border-white/5 p-4 rounded-3xl flex flex-col items-center shadow-xl">
             <span className="text-[7px] font-black text-muted-foreground uppercase tracking-[0.2em] mb-1">DISTANCA</span>
             <span className="text-sm font-black text-white">{(tripDistance / 1000).toFixed(2)} KM</span>
           </div>
           <div className="bg-zinc-900/40 border border-white/5 p-4 rounded-3xl flex flex-col items-center shadow-xl">
             <span className="text-[7px] font-black text-muted-foreground uppercase tracking-[0.2em] mb-1">MAX SPEED</span>
             <span className="text-sm font-black text-red-500">{peakSpeed} KM/H</span>
           </div>
        </div>

        {/* Action Button */}
        <div className="w-full max-w-[280px] space-y-3 stagger-3 apple-slide-up">
          <Button 
            onClick={() => isDriving ? handleStopMission() : handleStartMission()} 
            className={cn(
              "w-full h-16 rounded-full font-black text-sm uppercase tracking-widest transition-all shadow-2xl active:scale-95", 
              isDriving ? "bg-zinc-900 text-white" : "bg-red-600 hover:bg-red-700 text-white"
            )}
          >
            {isDriving ? "STOP TRIP" : "START TRIP"}
          </Button>
          
          {isNavigating && (
            <Button 
              onClick={() => clearNavigation()} 
              variant="outline"
              className="w-full h-12 rounded-full border-white/10 font-black text-[10px] uppercase tracking-widest text-zinc-500 hover:text-white"
            >
              NDALO NAVIGIMIN
            </Button>
          )}
        </div>
      </div>

      {/* Results Summary Dialog */}
      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="bg-[#0c0c0e] border-white/5 w-[94%] max-w-sm rounded-[2rem] p-0 overflow-hidden apple-scale-in max-h-[90vh] flex flex-col">
          <DialogClose className="absolute right-4 top-4 z-50 p-2 rounded-full bg-black/50 hover:bg-black/70 transition-colors">
            <X className="w-5 h-5 text-white" />
          </DialogClose>
          
          <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-5">
            <DialogHeader className="p-0 text-center flex flex-col items-center gap-2">
              <div className="w-12 h-12 rounded-full bg-red-600/20 flex items-center justify-center border border-red-500/20 shadow-2xl">
                <Trophy className="w-6 h-6 text-red-500" />
              </div>
              <div className="space-y-0.5">
                <DialogTitle className="text-xl font-black uppercase tracking-tight text-white">DRIVERANK PRO 🏆</DialogTitle>
                <DialogDescription className="text-[7px] font-black text-red-500 uppercase tracking-[0.3em]">STATISTIKAT E RRUGËTIMIT</DialogDescription>
              </div>
            </DialogHeader>
            
            <Card className="bg-zinc-900/40 border-white/5 p-4 rounded-[1.5rem] space-y-4 shadow-inner">
              <div className="h-36 w-full rounded-2xl border border-white/5 overflow-hidden relative shadow-2xl">
                 <RouteMap points={routePoints} />
              </div>

              <div className="grid grid-cols-3 gap-2">
                <div className="bg-zinc-950/50 p-3 rounded-xl flex flex-col items-center">
                  <Timer className="w-3 h-3 text-accent mb-1" />
                  <span className="text-[6px] font-black text-muted-foreground uppercase tracking-widest mb-0.5">KOHA</span>
                  <span className="text-[10px] font-black text-white tabular-nums">{formatTime(tripTime)}</span>
                </div>
                <div className="bg-zinc-950/50 p-3 rounded-xl flex flex-col items-center">
                  <MapPin className="w-3 h-3 text-accent mb-1" />
                  <span className="text-[6px] font-black text-muted-foreground uppercase tracking-widest mb-0.5">DISTANCA</span>
                  <span className="text-[10px] font-black text-accent tabular-nums">{(tripDistance / 1000).toFixed(2)}</span>
                </div>
                <div className="bg-zinc-950/50 p-3 rounded-xl flex flex-col items-center">
                  <Zap className="w-3 h-3 text-red-500 mb-1" />
                  <span className="text-[6px] font-black text-muted-foreground uppercase tracking-widest mb-0.5">MAX</span>
                  <span className="text-[10px] font-black text-red-500 tabular-nums">{peakSpeed}</span>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-1 pt-2 border-t border-white/5">
                 <div className="flex flex-col items-center">
                   <span className="text-[5px] font-black text-muted-foreground uppercase tracking-widest">MESATARJA</span>
                   <span className="text-[8px] font-black text-white">{avgSpeed} km/h</span>
                 </div>
                 <div className="flex flex-col items-center border-x border-white/5 px-0.5">
                   <span className="text-[5px] font-black text-muted-foreground uppercase tracking-widest">NDALESA</span>
                   <span className="text-[8px] font-black text-white">0</span>
                 </div>
                 <div className="flex flex-col items-center">
                   <span className="text-[5px] font-black text-muted-foreground uppercase tracking-widest">NXITIME</span>
                   <span className="text-[8px] font-black text-red-500">0</span>
                 </div>
              </div>
            </Card>

            <div className="space-y-3">
               <h3 className="text-[8px] font-black text-accent uppercase tracking-[0.2em] text-center">KALKULIMET E RANKING STATS</h3>
               <Card className="bg-zinc-900/40 border-white/5 p-4 rounded-[1.5rem] flex items-center gap-4 shadow-2xl">
                  <div className="w-10 h-10 rounded-xl bg-accent/20 flex items-center justify-center border border-accent/20">
                    <Star className="w-5 h-5 text-accent fill-accent" />
                  </div>
                  <div className="flex flex-col">
                    <span className="text-[8px] font-black text-accent uppercase tracking-widest">POZICIONI TUAJ</span>
                    <h4 className="text-sm font-black text-white leading-none mt-1 uppercase tracking-tight">
                      {isRankingLoading ? <Loader2 className="w-3 h-3 animate-spin inline" /> : `RANK #${cityRank || '--'} NË ${profile?.city?.toUpperCase() || 'KOSOVË'}`}
                    </h4>
                    <p className="text-[7px] font-black text-white/30 uppercase tracking-widest mt-1">
                      {kosovoRank ? `NR. ${kosovoRank} NË MBARË KOSOVËN` : "DUKE KALKULUAR..."}
                    </p>
                  </div>
               </Card>
            </div>

            <div className="flex flex-col gap-2 pt-2 pb-2">
              <Button onClick={handleSaveRun} disabled={isSaving || isRankingLoading} className="w-full h-12 bg-red-600 hover:bg-red-700 text-white rounded-[1.2rem] font-black uppercase text-[10px] tracking-widest transition-all active:scale-95 shadow-xl">
                {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : "Ruaj në Ranking"}
              </Button>
              <Button variant="ghost" className="w-full h-8 rounded-xl font-black uppercase text-[8px] text-zinc-600 tracking-widest hover:text-white" onClick={() => { setShowSummary(false); resetTrip(); }}>
                Fshij këtë rezultat
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
      <BottomNav />
    </div>
  );
}
